const source = $('Нормализатор').first().json;
const chatId = source.chat_id;

const agents = items
  .map(item => item.json)
  .filter(agent => agent.elevenlabs_agent_id && agent.display_name);

if (agents.length === 0) {
  return [
    {
      json: {
        chat_id: chatId,
        text: 'У вас пока нет доступных ElevenLabs agents.',
        button_1_text: '⬅️ Главное меню',
        button_1_callback: 'menu:main',
        button_2_text: '🤖 Обновить список',
        button_2_callback: 'agents:list',
        button_3_text: '🏠 Меню',
        button_3_callback: 'menu:main',
      },
    },
  ];
}

const safeName = (name) => String(name || '').replace(/_/g, ' ');

return [
  {
    json: {
      chat_id: chatId,
      text:
        'Выберите ElevenLabs agent для управления:\n\n' +
        agents.map((agent, index) => `${index + 1}. ${safeName(agent.display_name)}`).join('\n'),

      button_1_text: agents[0] ? safeName(agents[0].display_name) : '⬅️ Главное меню',
      button_1_callback: agents[0] ? `agent:${agents[0].elevenlabs_agent_id}` : 'menu:main',

      button_2_text: agents[1] ? safeName(agents[1].display_name) : '⬅️ Главное меню',
      button_2_callback: agents[1] ? `agent:${agents[1].elevenlabs_agent_id}` : 'menu:main',

      button_3_text: agents[2] ? safeName(agents[2].display_name) : '🏠 Меню',
      button_3_callback: agents[2] ? `agent:${agents[2].elevenlabs_agent_id}` : 'menu:main',
    },
  },
];

