SET
    current_action = '{{$json.next_action}}',
    updated_at = CURRENT_TIMESTAMP
WHERE telegram_user_id = {{$json.telegram_user_id}}
  AND selected_elevenlabs_agent_id = '{{$json.selected_elevenlabs_agent_id}}';

parameters.jsCode:
const session = $json;
const source = $('Нормализатор').first().json;

const newText = (source.message_text || '').trim();

if (!newText) {
  return [
    {
      json: {
        chat_id: source.chat_id,
        error: 'empty_text',
        text: 'Текст пустой. Отправьте непустое значение.',
      },
    },
  ];
}
const currentAction = session.current_action;
const agentId = session.selected_elevenlabs_agent_id;
const safeDisplayName = String(session.display_name || '').replace(/_/g, ' ');

let actionType = '';
let successText = '';
let requestBody = {};

if (currentAction === 'awaiting_prompt') {
  actionType = 'update_prompt';

  requestBody = {
    conversation_config: {
      agent: {
        prompt: {
          prompt: newText,
        },
      },
    },
    version_description: 'Prompt updated from Telegram bot',
  };

  successText = `Prompt обновлён для агента: ${safeDisplayName}`;
}

if (currentAction === 'awaiting_welcome_message') {
  actionType = 'update_welcome_message';

  requestBody = {
    conversation_config: {
      agent: {
        first_message: newText,
      },
    },
    version_description: 'Welcome message updated from Telegram bot',
  };

  successText = `Welcome message обновлён для агента: ${safeDisplayName}`;
}

if (currentAction === 'awaiting_knowledge_base') {
  actionType = 'update_knowledge_base';

  requestBody = {
    text: newText,
    name: `Telegram KB update - ${session.display_name}`,
  };

  successText = `Knowledge base document создан в ElevenLabs для агента: ${safeDisplayName}. В демо-версии документ создаётся в ElevenLabs Knowledge Base.`;
}

return [
  {
    json: {
      chat_id: source.chat_id,
      telegram_user_id: session.telegram_user_id,
      elevenlabs_agent_id: agentId,
      display_name: session.display_name,
      current_action: currentAction,
      action_type: actionType,
      new_text: newText,
      new_value_preview: newText.slice(0, 500),
      request_body: requestBody,
      success_text: successText,
    },
  },
];
